1	const PROCESSING_FEE = 5;
2	
3	interface Item {
4	  type: string;
5	  material: string;
6	  enchantment: number;
7	  cursed: boolean;
8	}
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const CURSED_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
25	const HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
26	
27	const FIRST_INSURANCE_RATE = 0.1;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_MIN_YEARS = 2;
30	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
31	
32	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	const itemPremium = (item: Item): number => {
37	  const base = basePremium(item);
38	  const curseSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
39	  const enchantmentSurcharge =
40	    item.enchantment >= HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD
41	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
42	      : 0;
43	  return base + curseSurcharge + enchantmentSurcharge;
44	};
45	
46	const componentBlockPremium = (type: string, count: number): number =>
47	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
48	
49	const countByType = (items: Item[]): Record<string, number> =>
50	  items.reduce<Record<string, number>>((counts, item) => {
51	    counts[item.type] = (counts[item.type] ?? 0) + 1;
52	    return counts;
53	  }, {});
54	
55	const componentsPremium = (components: Item[]): number =>
56	  Object.entries(countByType(components)).reduce(
57	    (sum, [type, count]) => sum + componentBlockPremium(type, count),
58	    0
59	  );
60	
61	const validateItems = (items: Item[]): void => {
62	  for (const item of items) {
63	    if (!(item.type in BASE_PREMIUMS)) {
64	      throw new Error(`Unknown item type: ${item.type}`);
65	    }
66	  }
67	};
68	
69	const itemsPremium = (items: Item[]): number => {
70	  const components = items.filter(isComponent);
71	  const nonComponents = items.filter((item) => !isComponent(item));
72	  const mainPremium = nonComponents.reduce(
73	    (sum, item) => sum + itemPremium(item),
74	    0
75	  );
76	  return mainPremium + componentsPremium(components);
77	};
78	
79	const INSURANCE_VALUES: Record<string, number> = {
80	  sword: 1000,
81	  amulet: 600,
82	  staff: 800,
83	  potion: 400,
84	  rune: 250,
85	  moonstone: 250,
86	};
87	
88	const DEDUCTIBLE = 100;
89	const HIGH_ENCHANTMENT_THRESHOLD = 8;
90	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
91	const CAP_MULTIPLIER = 2;
92	
93	const isHighEnchantment = (item: Item | undefined): boolean =>
94	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
95	
96	const reimbursableAmount = (policyItem: Item | undefined, damageAmount: number): number =>
97	  isHighEnchantment(policyItem)
98	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
99	    : damageAmount;
100	
101	const insuranceValue = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
102	
103	const totalInsuranceValue = (items: Item[]): number =>
104	  items.reduce((sum, item) => sum + insuranceValue(item), 0);
105	
106	export const claim = (
107	  policy: { items: Item[] },
108	  damages: { itemType: string; amount: number }[],
109	  remainingCap?: number
110	): { payout: number; remainingCap: number } => {
111	  const policyCounts = countByType(policy.items);
112	  const damageCounts: Record<string, number> = {};
113	  for (const d of damages) {
114	    if (d.amount < 0) {
115	      throw new Error(`Negative damage amount: ${d.amount}`);
116	    }
117	    damageCounts[d.itemType] = (damageCounts[d.itemType] ?? 0) + 1;
118	    if (damageCounts[d.itemType] > (policyCounts[d.itemType] ?? 0)) {
119	      throw new Error(`More damage entries than insured items for type: ${d.itemType}`);
120	    }
121	  }
122	  const cap = remainingCap ?? totalInsuranceValue(policy.items) * CAP_MULTIPLIER;
123	  const uncappedPayout = damages.reduce((sum, damage) => {
124	    const policyItem = policy.items.find((item) => item.type === damage.itemType);
125	    if (!policyItem) {
126	      throw new Error(`Item type not in policy: ${damage.itemType}`);
127	    }
128	    const reimbursement = reimbursableAmount(policyItem, damage.amount);
129	    return sum + Math.max(0, reimbursement - DEDUCTIBLE);
130	  }, 0);
131	  const payout = Math.floor(Math.min(uncappedPayout, cap));
132	  return { payout, remainingCap: cap - payout };
133	};
134	
135	export const quote = (
136	  customer: { yearsWithMHPCO: number },
137	  items: Item[],
138	  isFollowUp: boolean
139	): number => {
140	  validateItems(items);
141	  const itemsTotalPremium = itemsPremium(items);
142	  const policyBasePremium = items.reduce((sum, item) => sum + basePremium(item), 0);
143	  const firstInsurance = policyBasePremium * FIRST_INSURANCE_RATE;
144	  const loyaltyDiscount =
